    const dsnBlind = foundryRollMode2 === "blindroll";
    const dsnWhisper = foundryRollMode2 === "selfroll" ? [game.user.id] : foundryRollMode2 === "gmroll" ? game.users?.filter((u) => u.isGM).map((u) => u.id) : null;
