              const malusLabel = malusType === "attackMalus" ? game.i18n.localize("SRA2.FEATS.CYBERDECK.ATTACK") : game.i18n.localize("SRA2.FEATS.CYBERDECK.FIREWALL");
              ui.notifications?.info(`${targetName}: ${malusLabel} -${malusValue}`);
